import{_ as t,o as l,c as e,ag as i}from"./chunks/framework.WmBmIPw-.js";const p=JSON.parse('{"title":"模拟退火（Simulated Annealing, SA）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/simulated-annealing.md","filePath":"or-opt/simulated-annealing.md","lastUpdated":1777117704000}'),r={name:"or-opt/simulated-annealing.md"};function n(s,a,o,h,d,u){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="模拟退火-simulated-annealing-sa" tabindex="-1">模拟退火（Simulated Annealing, SA） <a class="header-anchor" href="#模拟退火-simulated-annealing-sa" aria-label="Permalink to &quot;模拟退火（Simulated Annealing, SA）&quot;">​</a></h1><p>模拟退火源于固体退火过程（加热再缓慢冷却以降低缺陷）。在组合/连续优化中，Kirkpatrick 等将其用于以可控概率<strong>接受变差的邻域移动</strong>，从而跳出局部最优。属于单点、基于邻域的元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：离散结构（TSP、调度、图划分等）的近似求解；目标为最小化时叙述最直观（最大化时符号相应改写）。</p><p><strong>核心</strong>：当前温度为 (T) 时，对能量升高 (\\Delta&gt;0) 的转移，以概率 (\\min(1,\\exp(-\\Delta/T))) 接受；(T) 随过程递减，后期几乎只接受改进。</p><hr><h2 id="算法-最小化示意" tabindex="-1">算法（最小化示意） <a class="header-anchor" href="#算法-最小化示意" aria-label="Permalink to &quot;算法（最小化示意）&quot;">​</a></h2><p>以目标函数 (f(s)) 在邻域内搜索（最小化；最大化可将「接受更差解」的准则改为对 (-f) 讨论）。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 模拟退火主循环（单解、邻域搜索）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>生成初始解 (s)（随机或经简单启发式），记当前最优解 (s^\\ast \\leftarrow s)。设初温 (T \\leftarrow T_0&gt;0)，并选定降温表与每温度下的内层步数/迭代次数。</p><h3 id="_2-同温内迭代" tabindex="-1">2. 同温内迭代 <a class="header-anchor" href="#_2-同温内迭代" aria-label="Permalink to &quot;2. 同温内迭代&quot;">​</a></h3><p>在温度 (T) 下，重复若干内层步，直到内层步数上限或同温收敛判据；每一步：</p><ul><li>由邻域算子自 (s) 生成候选解 (s&#39;)；</li><li>计算 (\\Delta = f(s&#39;)-f(s))；</li><li>若 (\\Delta \\le 0)，令 (s \\leftarrow s&#39;)；</li><li>若 (\\Delta&gt;0)，以概率 (\\min(1,\\exp(-\\Delta/T))) 令 (s \\leftarrow s&#39;)，否则保持 (s)；</li><li>若 (f(s)&lt;f(s^\\ast))（严格改进），更新 (s^\\ast \\leftarrow s)。</li></ul><h3 id="_3-降温" tabindex="-1">3. 降温 <a class="header-anchor" href="#_3-降温" aria-label="Permalink to &quot;3. 降温&quot;">​</a></h3><p>按预设计划更新 (T)（如 (T \\leftarrow \\alpha T)，(\\alpha\\in(0,1))），或按时间表降温。</p><h3 id="_4-终止" tabindex="-1">4. 终止 <a class="header-anchor" href="#_4-终止" aria-label="Permalink to &quot;4. 终止&quot;">​</a></h3><p>若 (T) 低于阈值、或达到总迭代/时间/无改进步数，则停；输出 (s^\\ast)。</p></div><hr><h2 id="关键要素" tabindex="-1">关键要素 <a class="header-anchor" href="#关键要素" aria-label="Permalink to &quot;关键要素&quot;">​</a></h2><ul><li><strong>解与邻域</strong>：问题依赖；邻域要足以连通可行域、且每步可高效计算 (f)。</li><li><strong>初温 (T_0)</strong>：过大则早期近似随机；过小则难以逃离局部优。可试算使初期接受率落在经验区间。</li><li><strong>降温与内层步数</strong>：过快的降温易早熟；过慢则计算量大。常配合多次运行或自适应策略。</li><li><strong>终止</strong>：最低温、总评估次数、最优解未改进次数等，按规模与实时性选择。</li></ul><h2 id="与同类方法的差异-提要" tabindex="-1">与同类方法的差异（提要） <a class="header-anchor" href="#与同类方法的差异-提要" aria-label="Permalink to &quot;与同类方法的差异（提要）&quot;">​</a></h2><ul><li>相对<strong>贪心/最速下降</strong>：允许暂时变差，利于探索。</li><li>相对<strong>禁忌搜索</strong>：不依赖显式长期禁忌表，用概率接受机制代替部分记忆。</li><li>可与其他方法<strong>混合</strong>（如大规模邻域、重启、局部搜索后处理）。</li></ul><h2 id="参考阅读" tabindex="-1">参考阅读 <a class="header-anchor" href="#参考阅读" aria-label="Permalink to &quot;参考阅读&quot;">​</a></h2><ul><li>Kirkpatrick, Gelatt, Vecchi, «Optimization by Simulated Annealing», 1983.</li><li>工程实现需结合具体问题的<strong>编码、邻域、不可行解处理</strong>等单独设计。</li></ul>',15)])])}const g=t(r,[["render",n]]);export{p as __pageData,g as default};
